#include <bits/stdc++.h>
using namespace std;
const int mod=998244353;
long long quick_mi(int a,long long b){
    long long sum=1,base=a;
    while(b){
        if(b&1)
            sum*=base,sum%=mod;
        b>>=1,base*=base,base%=mod;
    }
    return sum;
}
int main(){
    int n;
    long long ans=1;
    cin>>n;
    /*for(int i=1;i<=n;i++)
    	for(int j=1;j<=i;j++)
    		for(int k=1;k<=j;k++)
    			cout<<i<<' '<<j<<' '<<k<<'\n';*/
    for(int k=1;k<=n;k++){
		long long t=1LL*(2+n-k)*(1+n-k)/2;
		ans*=quick_mi(k,1LL*k*t),ans%=mod;
		//cout<<t<<' '<<ans<<'\n';
	}
    printf("%lld",ans);
    return 0;
}
